<script setup>
import { onBeforeUnmount, ref, watch } from 'vue';

import useNotificationsStore from '~/stores/notifications';

const props = defineProps({
  id: String,
});
const emit = defineEmits(['select']);
// not destructuring the store to avoid reactivity issue
const store = useNotificationsStore();
//
const select = ref(false);

/**
 * Applies the select action.
 */
function applySelect() {
  if (select.value) {
    // todo: is the watch function good enough ?
    select.value = false;
    store.selected.splice(store.selected.indexOf(props.id), 1);
  }
  else {
    // todo: is the watch function good enough ?
    select.value = true;
    if (!store.selected.includes(props.id))
      store.selected.push(props.id);
  }
  emit('select', select.value);
}

// Watches the selected notifications and updates the select value.
// double mesure to make sure the value is updated
watch(
  () => store.selected.length,
  () => {
    if (store.selected.includes(props.id))
      select.value = true;
    else select.value = false;
    emit('select', select.value);
  },
);
onBeforeUnmount(() => {
  // remove the selected notification
  emit('select', false);
});
</script>

<template>
  <div
    class="INTFCenter-selected-icon"
    :class="{ 'INTFCenter-color-3ds': select, 'INTFCenter-color-brown': !select }"
    @click="applySelect"
  >
    <span class="fonticon fonticon-status-ok text-2xl"></span>
  </div>
</template>
