<script setup>
import { VuInputDate } from '@ds/platformkit/components';
import { computed, inject, onMounted, ref } from 'vue';

import useTranslations from '~/composables/useTranslations';
import { getI18n } from '~/modules/imports';
import useFilterStore from '~/stores/filter';
import useSettingsStore from '~/stores/settings';

const { $i18n } = useTranslations();

const store = useFilterStore();
const settings = useSettingsStore();

const lang = ref('en');
const search = inject('search');

/**
 * Computed property that returns the tenants.
 * @returns {ComputedRef} The computed property for the tenants.
 */
const getTenants = computed(() => {
  const tenants = [];
  settings.tenants.tenants.forEach((tenant) => {
    if (!tenant.NAME)
      return;
    const tenantInfo = {
      value: tenant.PLATFORMID,
      label: tenant.NAME,
    };
    tenants.push(tenantInfo);
  });
  return tenants;
});

/**
 * Add search to a list of searches
 */
function addSearch() {
  const { addSearch } = useFilterStore();
  addSearch(search);
}

onMounted(async () => {
  const I18n = await getI18n();
  lang.value = I18n.getCurrentLanguage();
});

const maxDate = computed(() => {
  const date = store.filter.last_date;
  if (!date)
    return new Date(Date.now());

  return new Date(date);
});

const minDate = computed(() => {
  const date = store.filter.first_date;
  if (!date)
    return undefined;

  return new Date(date);
});
</script>

<template>
  <div class="INTFCenter-filter-section">
    <div class="INTFCenter-date-filter-section INTFCenter-start-date">
      <VuInputDate
        v-model="store.filter.first_date"
        :clearable="true"
        content-class="INTFCenter-filter-date INTFCenter-start-date"
        :date-format-locale="lang"
        :max="maxDate"
        :placeholder="$i18n('filterDateDefaultValue')"
      />
    </div>
    <span class="INTFCenter-color-brown text-sm block">{{ $i18n('to') }}</span>
    <div class="INTFCenter-date-filter-section INTFCenter-end-date">
      <VuInputDate
        v-model="store.filter.last_date"
        :clearable="true"
        content-class="INTFCenter-filter-date INTFCenter-end-date"
        :date-format-locale="lang"
        :max="new Date(Date.now())"
        :min="minDate"
        :placeholder="$i18n('filterDateDefaultValue')"
      />
    </div>
  </div>
  <!-- Search section -->
  <div class="INTFCenter-filter-search-section">
    <div class="INTFCenter-badge-searches">
      <vu-badge
        v-for="text in store.filter.searches"
        :key="text"
        closable
        color="default"
        selectable
        @close="store.filter.searches.splice(store.filter.searches.indexOf(text), 1)"
      >
        {{ text }}
      </vu-badge>
    </div>
    <div class="INTFCenter-search-input-container">
      <vu-input
        v-model="search"
        class="INTFCenter-filter-input"
        :placeholder="$i18n('searches')"
        @keyup.enter="addSearch"
      />
    </div>
  </div>
  <!-- read/unread/starred/unstarred section -->
  <div class="INTFCenter-filter-checkbox INTFCenter-color-brown">
    <div class="INTFCenter-read-checkbox">
      <vu-single-checkbox v-model="store.filter.read" class="INTFCenter-read-read-checkbox" :label="$i18n('read')" />
      <vu-single-checkbox
        v-model="store.filter.unread"
        class="INTFCenter-read-unread-checkbox"
        :label="$i18n('unread')"
      />
    </div>
    <div class="INTFCenter-starred-checkbox">
      <vu-single-checkbox
        v-model="store.filter.starred"
        class="INTFCenter-starred-starred-checkbox"
        :label="$i18n('starred')"
      />
      <vu-single-checkbox
        v-model="store.filter.unstarred"
        class="INTFCenter-starred-unstarred-checkbox"
        :label="$i18n('unstarred')"
      />
    </div>
  </div>

  <!-- filter tenant section -->
  <div v-if="!settings.hidePlatformSelection && !!settings.isTenantAgnostic">
    <vu-multiple-select
      v-model="store.filter.tenants"
      class="INTFCenter-filter-platform-section"
      :options="getTenants"
      :placeholder="$i18n('platformsSelection')"
    />
  </div>
</template>
