<script setup>
import { toRef } from 'vue';

import TogglePreference from '~/components/BaseCenter/CenterBody/Preferences/App/TogglePreference.vue';
import { useAppOption } from '~/composables/preferences/App/useAppOption';
import { useToggleHelper } from '~/composables/preferences/useToggleHelper';
import useTranslations from '~/composables/useTranslations';

const props = defineProps({
  option: {
    type: Object,
    required: true,
  },
  settingId: {
    type: Number,
    required: true,
  },
});

const { $i18n } = useTranslations();

const {
  state,
  isReadOnly,
  updateState,
  updateReadOnly,
} = useToggleHelper(toRef(props, 'settingId'), toRef(props, 'option'));

const {
  displayOption,
  cursorReadOnly,
  tooltipText,
  needToggle,
  optionEnabled,
  updateSetting,
} = useAppOption({
  settingId: toRef(props, 'settingId'),
  option: toRef(props, 'option'),
});
</script>

<template>
  <div
    v-if="displayOption"
    class="INTFCenter-desktop"
    :class="[
      `INTFCenter-option-${option.name}`,
      { 'INTFCenter-cursor-readonly': cursorReadOnly },
    ]"
    data-testid="app-option-logo-container"
    :title="tooltipText"
    @click="updateSetting"
  >
    <span :class="[option.fonticonName, `intfnotif-${optionEnabled ? 'on' : 'off'}`]"> </span>

    <span :class="`intfnotif-${optionEnabled ? 'on' : 'off'}`"> {{ $i18n(`${option.name}IconText`) }} </span>
  </div>
  <TogglePreference
    v-if="needToggle"
    :lock="isReadOnly"
    :toggle-value="state"
    @lock-update="updateReadOnly"
    @toggle-update="updateState"
  />
</template>
