<script setup>
import { computed } from 'vue';

import { NotificationTrackerUsage } from '~/api/tracker';
import useTranslations from '~/composables/useTranslations';
import mobileDevice from '~/functions/device';
import useNotificationsStore from '~/stores/notifications';

const { $i18n } = useTranslations();
const store = useNotificationsStore();

/**
 * Activates/Deactivates the selection mode.
 */
function activateSelectionMode() {
  const { multipleSelectionActionTracker } = NotificationTrackerUsage();
  const selectionModeTracker = multipleSelectionActionTracker();
  store.selectionMode = !store.selectionMode;

  // analytics
  if (store.selectionMode)
    selectionModeTracker.enableSelection();
  else
    selectionModeTracker.disableSelection();
}

/**
 * Computes the length of something.
 *
 * @returns {number} The computed length.
 */
const length = computed(() => {
  return store.selected.length;
});

/**
 * Computed property that returns the length of the text.
 * returns 99+ if the length is greater than 99.
 * @returns {number} The length of the text.
 */
const lengthText = computed(() => {
  return length.value > 99 ? '99+' : length.value;
});
</script>

<template>
  <div class="INTFCenter-select-notification">
    <vu-btn
      v-tooltip.left="!mobileDevice ? $i18n('multiSelection') : undefined"
      class="INTFCenter-btn-transparent"
      :class="{ 'INTFCenter-btn-active': store.selectionMode, 'INTFCenter-btn-hover': !store.selectionMode }"
      large
      @click="activateSelectionMode"
    >
      <span
        class="fonticon INTFCenter-multi-select-icon"
        :class="{
          'fonticon-select-off ': !store.selectionMode,
          'fonticon-select-on ': store.selectionMode,
        }"
      ></span>
    </vu-btn>
    <span
      v-show="length > 0"
      class="text-xs cursor-default INTFCenter-color-3ds INTFCenter-nb-notif-selected"
      :title="`${length > 99 ? `${length} ${$i18n('selected')}` : ''}`"
    >
      {{ lengthText }}</span>
  </div>
</template>
