<script setup>
import { computed, nextTick, ref, watch } from 'vue';

import { NotificationTrackerUsage } from '~/api/tracker';
import NotificationMenu from '~/components/BaseCenter/CenterBody/Notification/NotificationBody/NotificationMenu.vue';
import Filter from '~/components/BaseCenter/CenterHeader/Toolbar/Filter.vue';
import SelectTool from '~/components/BaseCenter/CenterHeader/Toolbar/SelectTool.vue';
import Setting from '~/components/BaseCenter/CenterHeader/Toolbar/Setting.vue';
import useTranslations from '~/composables/useTranslations';
import useNotificationsStore from '~/stores/notifications';

import { selectMenu, selectMenuDisabled } from '~/services/menu';

const { $i18n } = useTranslations();
const { multipleSelectionActionTracker } = NotificationTrackerUsage();
const store = useNotificationsStore();

// Check if selection mode is active
const selectionMode = computed(() => {
  return store.selectionMode === true;
});

// Check if there are more than one notification
// to display or not the checkbox for selection
const hasNotification = computed(() => {
  return store.notifications.size > 0;
});
// Check if there are more notifications to select
const canSelectMore = computed(() => {
  return store.selected.length < store.notifications.size;
});

// Check if nothing is selected
const nothingSelected = computed(() => {
  return store.selected.length === 0;
});

// Returns boolean. Checks if at least one notification is not marked as important
const canMarkAsStarredMore = computed(() => {
  for (const key of store.notifications.keys()) {
    if (store.selected.includes(key) && (store.notifications.get(key).STARRED === 0)) {
      return (store.notifications.get(key).STARRED === 0);
    }
  }
  return store.selected.length === -1;
});

// Returns boolean. Checks if at least one notification is not marked as unstarred
const canMarkSelectedAsUnstarred = computed(() => {
  for (const key of store.notifications.keys()) {
    if (store.selected.includes(key) && (store.notifications.get(key).STARRED === 1)) {
      return (store.notifications.get(key).STARRED === 1);
    }
  }
  return store.selected.length === -1;
});

// Returns boolean. Checks if at least one notification is not marked as read
const canMarkAllAsRead = computed(() => {
  for (const key of store.notifications.keys()) {
    if (store.selected.includes(key) && store.notifications.get(key).READ_DATE === null) {
      return (!store.notifications.get(key).READ_DATE);
    }
  }
  return store.selected.length === -1;
});

// Returns boolean. Checks if at least one notification is not marked as unread
const canMarkAllAsUnread = computed(() => {
  for (const key of store.notifications.keys()) {
    if (store.selected.includes(key) && store.notifications.get(key).READ_DATE !== null) {
      return (!!store.notifications.get(key).READ_DATE);
    }
  }
  return store.selected.length === -1;
});

// Select all notifications
function selectAllNotification() {
  for (const key of store.notifications.keys()) {
    // If the notification is not selected and not deleted, add it to the selected array
    if (!store.selected.includes(key) && !store.notifications.get(key).deleted)
      store.selected.push(key);
  }

  // analytics
  multipleSelectionActionTracker()
    .selectionAction({ action: 'selectAllNotifications', length: store.selected.length });
}

const menu = ref([]);
// Menu options when no notification is selected
// the only callback needed is the select all
const menuDisabled = ref(selectMenuDisabled(selectAllNotification));

/**
 * Unselects all notifications.
 */
function unselectAllNotification() {
  const length = store.selected.length;
  for (let i = 0; i < length; i++) {
    store.selected.pop();
  }
}
// update the select all option text
watch(canSelectMore, (n) => {
  if (menu.value.length > 0)
    menu.value[0].text = n ? $i18n('selectAll') : $i18n('unselectAll');
  if (menuDisabled.value.length > 0)
    menuDisabled.value[0].text = n ? $i18n('selectAll') : $i18n('unselectAll');
});

// Watch for changes in a single notification to update the select menu
watch(
  () => store.notifications.get(store.selected[0]),
  (n) => {
    if (store.selected.length === 1) {
      menu.value = selectMenu({
        canSelectMore: canSelectMore.value,
        moreThanOneSelected: false,
        selectAll: selectAllNotification,
        unSelectAll: unselectAllNotification,
      })
        .concat(n.getOptions);
    }
  },
  { deep: true },
);

// Watch the selected notifications AND the selected action from the menu THEN update the select menu
watch(
  () => [store.selected.length, canMarkAsStarredMore, canMarkSelectedAsUnstarred, canMarkAllAsRead, canMarkAllAsUnread],
  async (n) => {
    // If no notification is selected, only enable the select all option
    if (n[0] === 0) {
      menu.value = menuDisabled.value;
    }
    // If one or more notifications are selected, display the options
    else {
      // Display the selected notification options
      if (n[0] === 1) {
        menu.value = selectMenu({
          canSelectMore: canSelectMore.value,
          moreThanOneSelected: false,
          selectAll: selectAllNotification,
          unselectAll: unselectAllNotification,
          canMarkAsStarredMore,
          canMarkSelectedAsUnstarred,
          canMarkAllAsRead,
          canMarkAllAsUnread,
        })
          .concat(store.getNotificationById(store.selected[0]).getOptions);
      }
      // If more than one notification is selected, display the options for multiple notifications
      else {
        menu.value = selectMenu({
          canSelectMore: canSelectMore.value,
          moreThanOneSelected: true,
          selectAll: selectAllNotification,
          unselectAll: unselectAllNotification,
          canMarkAsStarredMore,
          canMarkSelectedAsUnstarred,
          canMarkAllAsRead,
          canMarkAllAsUnread,
        });
      }
    }
    await nextTick();
  },
  { deep: true },
);

// Empty the selected array when selectionMode value changes
watch(selectionMode, () => {
  unselectAllNotification();
});
</script>

<template>
  <div class="INTFCenter-notif-center-toolbar INTFCenter-color-brown text-lg">
    <div class="INTFCenter-select-wrapper">
      <TransitionGroup name="select-menu">
        <NotificationMenu
          v-if="selectionMode && hasNotification"
          class="INTFCenter-select-menu INTFCenter-select-menu-notification"
          :options="nothingSelected ? menuDisabled : menu"
        />
      </TransitionGroup>
      <SelectTool v-if="hasNotification" />
    </div>
    <Filter />
    <Setting />
  </div>
</template>
