<script setup>
import { ref, watch } from 'vue';

import useTranslations from '~/composables/useTranslations';
import mobileDevice from '~/functions/device';
import useFilterStore from '~/stores/filter';
import useNotificationsStore from '~/stores/notifications';
import useSettingsStore from '~/stores/settings';

import { settingsMenu } from '~/services/menu';

const { $i18n } = useTranslations();

// not destructuring the store to avoid reactivity issue
const store = useNotificationsStore();
// not destructuring the store to avoid reactivity issue
const settingsStore = useSettingsStore();
// not destructuring the store to avoid reactivity issue
const filterStore = useFilterStore();
//
const more = ref(false);
const settingModel = ref([]);

const menu = ref(settingsMenu());

// watch for changes to rebuild the menu
watch(
  () => [
    store.isEmpty,
    filterStore.isFilterApplied(),
    settingsStore.hidePlatformSelection,
    settingsStore.getPlatformPreferencesAccess(),
  ],
  () => menu.value = settingsMenu(),
);
</script>

<template>
  <div class="INTFCenter-setting-div">
    <vu-dropdownmenu
      v-model="settingModel"
      :items="menu"
      position="bottom-right"
      @close="more = false"
    >
      <vu-btn
        v-tooltip.left="!mobileDevice ? $i18n('settings') : undefined"
        class="INTFCenter-btn-transparent INTFCenter-setting-btn"
        :class="{ 'INTFCenter-btn-active': more, 'INTFCenter-btn-hover': !more }"
        large
        @click="more = true"
      >
        <span class="fonticon fonticon-cog INTFCenter-toolbar-icon"></span>
      </vu-btn>
    </vu-dropdownmenu>
  </div>
</template>
