import { getServiceUrl } from "../compass/compass-services.js";
import { SERVICE } from "../compass/services.js";
async function logout(path, { redirectToPassportLogin } = { redirectToPassportLogin: true }) {
  const passportUrl = await getServiceUrl(SERVICE.PASSPORT);
  if (window.location.href.startsWith(passportUrl))
    return;
  const passportLogoutUrl = new URL(`${passportUrl}/logout`);
  const redirectTo = path ?? window.location.href;
  if (redirectToPassportLogin) {
    const passportLoginUrl = new URL(`${passportUrl}/login`);
    passportLoginUrl.searchParams.set("service", redirectTo);
    passportLogoutUrl.searchParams.set("redirect", btoa(passportLoginUrl.toString()));
  } else {
    passportLogoutUrl.searchParams.set("service", redirectTo);
  }
  window.location.href = passportLogoutUrl.toString();
}
export {
  logout
};
