<script setup>
import { computed } from 'vue';

import { NotificationTrackerUsage } from '~/api/tracker';
import useTranslations from '~/composables/useTranslations';
import mobileDevice from '~/functions/device';
import useFilterStore from '~/stores/filter';

const storeFilter = useFilterStore();
const opened = computed(() => {
  return storeFilter.opened;
});

const { $i18n } = useTranslations();

/**
 * Sets the the filter opened state.
 */
function setOpened() {
  // analytics
  const { notificationFilterViewTracker } = NotificationTrackerUsage();
  const filterViewTracker = notificationFilterViewTracker();
  //
  if (opened.value) {
    storeFilter.setOpened(false);
    // tracker for filter icon click (hide)
    filterViewTracker.clicknotifFilterIconToHide();
  }
  else {
    storeFilter.setOpened(true);
    // tracker for filter icon click (show)
    filterViewTracker.clicknotifFilterIconToShow();
  }
}
</script>

<template>
  <div class="INTFCenter-filter-tool">
    <vu-btn
      v-tooltip.left="!mobileDevice ? $i18n('filter') : undefined"
      class="INTFCenter-btn-transparent INTFCenter-filter-btn"
      :class="{
        'INTFCenter-btn-active': opened || storeFilter.applied,
        'INTFCenter-btn-hover': !opened && !storeFilter.applied,
      }"
      large
      @click="setOpened"
    >
      <span class="fonticon fonticon-filter INTFCenter-toolbar-icon"></span>
    </vu-btn>
  </div>
</template>
