<script setup>
import useTranslations from '~/composables/useTranslations';

const props = defineProps({
  id: String,
});

const emit = defineEmits(['cancelDeletion']);

const { $i18n } = useTranslations();

function cancelDeletion() {
  emit('cancelDeletion', props.id);
}
</script>

<template>
  <div class="INTFCenter-notification-is-deleted">
    <p class="INTFCenter-deleted-text INTFCenter-color-brown">
      {{ $i18n('notificationDeleted') }}
    </p>
    <vu-btn
      class="INTFCenter-cancel-btn"
      color="primary"
      small
      @click="cancelDeletion"
    >
      <span class="fonticon fonticon-reload"></span>
      <span class="INTFCenter-deletion-msg">{{ $i18n('cancel') }}</span>
    </vu-btn>
  </div>
</template>
