<script setup>
import { provide, ref } from 'vue';

import { NotificationTrackerUsage } from '~/api/tracker';
import FilterButtons from '~/components/BaseCenter/CenterHeader/FilterBody/FilterButtons.vue';
import FilterOptions from '~/components/BaseCenter/CenterHeader/FilterBody/FilterOptions.vue';
import { useFilterManagement } from '~/composables/filter/useFilterManagement';
import useFilterStore from '~/stores/filter';

const { setOpened } = useFilterStore();
const { notificationFilterViewTracker } = NotificationTrackerUsage();
const filterViewTracker = notificationFilterViewTracker();
//

const search = ref('');
//
provide('search', search);
/**
 * Resets the filter.
 */
function _resetFilter() {
  // analytics
  filterViewTracker.resetFilterFields();
  //
  const { resetFilter } = useFilterManagement();
  resetFilter();
}

/**
 * Apply the filter.
 */
function _applyFilter() {
  //
  const { applyFilter } = useFilterManagement();
  applyFilter(search);
  // analytics
  // wait for the filter to be applied for 5 seconds to get the correct filter count
  setTimeout(() => {
    // analytics
    filterViewTracker.clickFilterButton();
  }, 5000); // todo: bad practice, filterCount could change while waiting (false positive)
}

/**
 * Closes the filter.
 */
function closeFilter() {
  // analytics
  filterViewTracker.cancelFilterView();
  //
  setOpened(false);
}
</script>

<template>
  <vu-form class="INTFCenter-filter">
    <!-- Filter Options -->
    <FilterOptions />
    <!-- Filter, reset, close section -->
    <FilterButtons
      @apply="_applyFilter"
      @close="closeFilter"
      @reset="_resetFilter"
    />
  </vu-form>
</template>
