<script setup>
import { VuSingleCheckbox } from '@ds/platformkit/components';
import { toRef, watch } from 'vue';

import { useTogglePreference } from '~/composables/preferences/App/useTogglePreference';

const props = defineProps({
  needDropDown: {
    type: Boolean,
    default: false,
  },
  icon: {
    type: String,
    default: null,
  },
  description: {
    type: String,
    default: '',
  },
  lock: {
    type: Boolean,
    default: null,
  },
  toggleValue: {
    type: Boolean,
    default: null,
  },
});

const emit = defineEmits(['chevronUpdate', 'lockUpdate', 'toggleUpdate']);

const {
  lockTitle,
  isRevertingToggle,
  lockContainerClass,

  chevronClass,
  needLock,
  lockClass,
  needToggle,
  toggleEnable,
  isDisabled,

  revertToggleEnable,
  toggleDropdown,
  getLockClassValue,
  revertLock,
  canUpdateLock,
  handleClickNotAllowed,
} = useTogglePreference({
  needDropDown: toRef(props, 'needDropDown'),
  lock: toRef(props, 'lock'),
  toggleValue: toRef(props, 'toggleValue'),
});

function toggleDropdownUpdate() {
  const newValue = toggleDropdown();
  if (newValue !== null)
    emit('chevronUpdate', newValue);
}

function switchLockValue() {
  if (canUpdateLock()) {
    lockClass.value = getLockClassValue(!props.lock);

    emit('lockUpdate', !props.lock, revertLock);
  }
}

watch(toggleEnable, (newValue, oldValue) => {
  if (newValue !== props.toggleValue && !isRevertingToggle.value) {
    emit('toggleUpdate', newValue, revertToggleEnable.bind(null, oldValue));
  }
  else {
    isRevertingToggle.value = false;
  }
});
</script>

<template>
  <div class="INTFCenter-toggle-preference-container grid-container">
    <div
      v-if="needDropDown"
      class="INTFCenter-app-setting-drop-down INTFCenter-btn-preference-chevron cursor-pointer item-1"
      data-testid="toggle-preference-dropdown"
      @click="toggleDropdownUpdate"
    >
      <span
        class="fonticon"
        :class="chevronClass"
        style="margin: 0px; font-size: .5rem;
            line-height: 1; max-width: 8px; margin:auto; padding:auto"
      ></span>
    </div>
    <div
      class="item-2 "
      :class="{ /* 'INTFCenter-preference-appname-off': settingOff() */ 'cursor-pointer': needDropDown }"
      data-testid="description-preference-dropdown"
      style="margin: auto auto auto 0;"
      @click="toggleDropdownUpdate"
    >
      <div
        v-if="icon"
        class="logo-container"
        style="padding: 0 14px;"
        title="Mail notifications disabled"
      >
        <span class="fonticon logo fonticon-2x" :class="icon"></span>
      </div>

      <div class="INTFCenter-appSetting-appTitle">
        {{ description }}
      </div>
    </div>

    <div
      v-if="needLock"
      class="INTFCenter-toggle-preference-lock INTFCenter-btn-transparent-default item-3"
      :class="lockContainerClass"
      data-testid="toggle-preference-lock-container"
      @click="switchLockValue"
    >
      <span
        class="fonticon"
        :class="lockClass"
        style="margin: 0px;"
        :title="lockTitle"
      ></span>
    </div>

    <div
      v-if="needToggle"
      class="item-4 INTFCenter-appSetting-option"
      :class="{ 'INTFCenter-toggle-preference-not-allowed': isDisabled }"
      data-testid="toggle-preference-switch-container"
      @click="handleClickNotAllowed"
    >
      <VuSingleCheckbox
        v-model="toggleEnable"
        :disabled="isDisabled"
        switch
      />
    </div>
  </div>
</template>

