<script setup>
import { useNotificationMenu } from '~/composables/notification/useNotificationMenu';
import { Notification } from '~/models/notification';

const props = defineProps({
  isRead: {
    type: Boolean,
    default: false,
  },
  isStarred: {
    type: Boolean,
    default: false,
  },
  notification: {
    type: Notification,
  },
});

const notificationMenu = useNotificationMenu();
</script>

