  <div class="INTFCenter-notif-status">
    <span
      v-if="isRead && !isStarred"
      class="INTFCenter-read-unread INTFCenter-notification-read cursor-pointer"
      @click="notificationMenu.setNotificationRead(props.notification)"
    ></span>
    <span
      v-if="!isRead && !isStarred"
      class="INTFCenter-read-unread INTFCenter-notification-unread cursor-pointer"
      @click="notificationMenu.setNotificationRead(props.notification)"
    ></span>
    <span v-if="isRead && isStarred" class="INTFCenter-notification-important fonticon fonticon-favorite-off"></span>
    <span
      v-if="!isRead && isStarred"
      class="INTFCenter-notification-important fonticon fonticon-favorite-on font-semibold"
    ></span>
  </div>
</template>
