<script setup>
import { watchOnce } from '@vueuse/core';
import { onMounted, provide } from 'vue';

import { filter, getUnreadTotal } from '~/api/senders';
import NotificationCenter from '~/components/BaseCenter/BaseCenter.vue';
import BasePreferences from '~/components/BaseCenter/BasePreferences.vue';
import { useConnection } from '~/composables/connection/useConnection';
import { usePreferencesManagement } from '~/composables/preferences/usePreferencesManagement';
import useFilterStore from '~/stores/filter';
import useNotificationsStore from '~/stores/notifications';
import useSettingsStore from '~/stores/settings';

const { watchSettingWithUnsubDate } = usePreferencesManagement();
const { reliveSocketIfKO, setSocketStatusTimeout } = useConnection();
const { loadFilter } = useFilterStore();
const store = useNotificationsStore();
const settingStore = useSettingsStore();

// Needed this for the date inputs to work
provide('vuDebug');

/**
 * Loads data.
 */
function loadData() {
  const { isFilterApplied, getFilter } = useFilterStore();

  // Ensure that if no filter was applied, we use the default filter (unread notifications only)
  const payload = getFilter();
  if (!isFilterApplied()) {
    getUnreadTotal();
  }

  filter(payload);
}

onMounted(async () => {
  store.setIsLoading(true);
  loadFilter();
  // wait for clusterId before sending get history / filter
  if (store.clusterId)
    loadData();
  else watchOnce(() => store.clusterId, loadData);
  // watch and reset setting with unsub date when timeout
  watchSettingWithUnsubDate();
  // set socket status timeout
  // status will reverse to false if not changed after 10 seconds
  setSocketStatusTimeout(10000);
  // get data on socket status change
  // will get socket status then watch for changes and get data if socket is connected after a deconnection
  reliveSocketIfKO();
});
</script>

<template>
  <div class="INTFCenter-app-vue-notif">
    <vu-modal-container>
      <template #modal-body>
        <div v-if="store.hasRenderToDoc" v-html="store.renderToDoc"></div>
      </template>
    </vu-modal-container>
    <div class="INTFCenter-message-modal">
      <vu-message-container />
    </div>

    <div class="INTFCenter-notification-app">
      <Transition name="base-center">
        <NotificationCenter v-if="settingStore.getWindowShow() === 'CENTER'" />
        <BasePreferences v-else />
      </Transition>
    </div>
  </div>
</template>
