import ky from "ky";
import { passportAuth } from "./modules/auth.js";
import { addRequestId } from "./modules/request-id.js";
const dsFetch = ky.extend({
  credentials: "include",
  redirect: "error",
  headers: {
    "x-requested-with": "XMLHttpRequest",
    "content-type": "application/json;charset=UTF-8"
  },
  timeout: 25e3,
  hooks: {
    beforeRequest: [addRequestId],
    afterResponse: [passportAuth]
  }
});
export {
  dsFetch
};
