<script setup>
import { computed } from 'vue';

import GlobalApp from '~/components/BaseCenter/CenterBody/Preferences/GlobalApp.vue';
import useSettingsStore from '~/stores/settings';

const store = useSettingsStore();

/**
 * Computed property that returns the global app.
 *
 * @returns {ComputedRef} The computed global app.
 */
const globalApp = computed(() => {
  return store.getAllGroupSettings;
});
</script>

<template>
  <!-- Preferences app list  -->
  <div class="INTFCenter-preferences INTFCenter-preferences-home">
    <vu-scroller class="INTFCenter-preferences-body">
      <TransitionGroup name="list">
        <div v-for="setting in globalApp" :key="setting.id">
          <GlobalApp :setting="setting" />
        </div>
      </TransitionGroup>
    </vu-scroller>
  </div>
</template>
