const XRequestIdHeader = "X-Request-ID";
const addRequestId = (request) => {
  if (!request.headers.has(XRequestIdHeader))
    request.headers.append(XRequestIdHeader, crypto.randomUUID());
  if (!request.headers.get(XRequestIdHeader))
    request.headers.delete(XRequestIdHeader);
};
const removeRequestId = (request) => {
  if (request.headers.has(XRequestIdHeader))
    request.headers.delete(XRequestIdHeader);
};
export {
  XRequestIdHeader,
  addRequestId,
  removeRequestId
};
