<script setup>
import { computed, ref } from 'vue';

import useNotificationsStore from '~/stores/notifications';

defineProps({
  options: Object,
  isRead: {
    type: Boolean,
    default: false,
  },
});
// not destructuring the store to avoid reactivity issue
const store = useNotificationsStore();
//
/**
 * Computed property that returns the scrollerBody value from the store.
 * @returns {any} The scrollerBody value from the store.
 */
const scroller = computed(() => store.scrollerBody);
/**
 * Toggle the menu action.
 */
const menuAction = ref(false);
/**
 * Represents the selected action in the notification menu.
 */
const selectedAction = ref([]);

/**
 * Opens the notification menu.
 */
function openMenu() {
  menuAction.value = true;
}
</script>

<template>
  <div class="INTFCenter-dropdown-menu-div">
    <vu-dropdownmenu
      v-model="selectedAction"
      :attach="scroller"
      :items="options"
      position="bottom-right"
      @close="menuAction = false"
    >
      <vu-btn
        class="INTFCenter-btn-transparent INTFCenter-menu-btn"
        :class="{
          'INTFCenter-btn-active': menuAction,
          'INTFCenter-btn-hover': !menuAction,
          'INTFCenter-is-read': isRead,
        }"
        large
        @click="openMenu"
      >
        <span class="fonticon fonticon-chevron-down INTFCenter-menu-icon"></span>
      </vu-btn>
    </vu-dropdownmenu>
  </div>
</template>
