<script setup>
import useTranslations from '~/composables/useTranslations';

const emit = defineEmits(['close', 'apply', 'reset']);
const { $i18n } = useTranslations();
function closeFilter() {
  emit('close');
}
function resetFilter() {
  emit('reset');
}
function applyFilter() {
  emit('apply');
}
</script>

<template>
  <div class="INTFCenter-filter-footer">
    <div class="INTFCenter-filter-bottom-container">
      <div class="INTFCenter-bottom-filter">
        <vu-btn class="INTFCenter-filter-btn-filter" color="primary" @click="applyFilter">
          {{ $i18n('filter') }}
        </vu-btn>
        <vu-btn class="INTFCenter-filter-btn-reset" @click="resetFilter">
          {{ $i18n('reset') }}
        </vu-btn>
        <vu-btn class="INTFCenter-filter-btn-close" @click="closeFilter">
          {{ $i18n('close') }}
        </vu-btn>
      </div>
    </div>
  </div>
</template>
