<script setup>
import { VuMessage } from '@ds/platformkit/components';
import { computed, onBeforeMount } from 'vue';

import { NotificationTrackerUsage } from '~/api/tracker';
import PreferencesHome from '~/components/BaseCenter/CenterBody/Preferences/PreferencesHome.vue';
import SettingHomeList from '~/components/BaseCenter/CenterBody/Preferences/SettingHomeList.vue';
import { usePreferencesManagement } from '~/composables/preferences/usePreferencesManagement';
import useTranslations from '~/composables/useTranslations';
import useSettingsStore from '~/stores/settings';

const { $i18n } = useTranslations();
const store = useSettingsStore();

/**
 * Computed property that determines if the settings are currently being loaded.
 * @returns {boolean} True if the settings are being loaded, false otherwise.
 */
const loading = computed(() => store.settingState.isLoading.settings === true);
const isDND = computed(() => store.isDND === true);

/**
 * Function to navigate back to the center or settings.
 */
function backToCenterOrSetting() {
  const { notificationSettingViewTracker } = NotificationTrackerUsage();
  const settingsViewTracker = notificationSettingViewTracker();
  if (store.appSettingOpened) {
    store.setAppSettingOpened(false);
    // analytics
    settingsViewTracker.backtoNotificationSettingsView();
  }
  else {
    store.setWindoShow('CENTER');
    // analytics
    settingsViewTracker.backtoNotificationCenterView();
  }
}

const textBackButton = store.getWindowShow() === 'PREFERENCES' ? 'preferences' : 'platformpreferences';
const alertText = computed(() =>
  store.getWindowShow() === 'PLATFORM_PREFERENCES'
    ? `${$i18n('messagePreventplatformpreferences')} ${store.getCurentTenantName()}`
    : isDND.value
      ? $i18n('dndAlertMsg')
      : null);

onBeforeMount(() => {
  const { loadSettings } = usePreferencesManagement();
  loadSettings(); // will load the settings if not loaded
});

const components = {
  PreferencesHome,
  SettingHomeList,
};
</script>

<template>
  <div class="INTFCenter-base-preferences">
    <button
      class="INTFCenter-preferences-go-back-button INTFCenter-btn-transparent-default"
      data-testid="base-preferences-go-back"
      @click="backToCenterOrSetting"
    >
      <span class="fonticon INTFCenter-btn-hover fonticon-chevron-left INTFCenter-back-icon"></span>
      <span class="INTFCenter-color-brown">{{ $i18n(textBackButton) }}</span>
    </button>

    <VuMessage
      v-if="alertText"
      color="warning"
      :is-closable="false"
      :text="alertText"
    />

    <div v-if="loading" class="INTFCenter-spinner-container">
      <vu-spinner />
    </div>

    <Transition v-else name="setting">
      <div class="INTFCenter-preferences">
        <Transition name="base-center">
          <component
            :is="components[store.appSettingOpened ? 'SettingHomeList' : 'PreferencesHome']"
            :setting-id="store.currentSetting"
          />
        </Transition>
      </div>
    </Transition>
  </div>
</template>
